module adder_32bit(
    input [32:1] A, B,
    output [32:1] S,
    output C32
);

wire [32:1] P, G, C;

assign P = A ^ B;
assign G = A & B;

wire [16:1] P1, G1;
assign P1 = P[16:1];
assign G1 = G[16:1];

wire C1;
assign C1 = G1[1] | (P1[1] & C[1]);

wire [8:1] P2, G2;
assign P2 = P1[8:1];
assign G2 = G1[8:1];

wire C2;
assign C2 = G2[1] | (P2[1] & C1);

wire [4:1] P3, G3;
assign P3 = P2[4:1];
assign G3 = G2[4:1];

wire C3;
assign C3 = G3[1] | (P3[1] & C2);

wire [2:1] P4, G4;
assign P4 = P3[2:1];
assign G4 = G3[2:1];

wire C4;
assign C4 = G4[1] | (P4[1] & C3);

wire P5, G5;
assign P5 = P4[1];
assign G5 = G4[1];

wire C5;
assign C5 = G5 | (P5 & C4);

assign S[1] = P[1];
assign S[16:2] = P1[15:1] ^ C[1:15];
assign S[32:17] = P2[15:0] ^ C[16:1];
assign C32 = C5;

endmodule
